  ('comedy-odyssey-the-salisbury-hotel', 'Comedy Odyssey', 'An exciting night of stand-up, hosted by Kallis Kyriacou. A chance to see the best up-and-coming acts in London alongside experienced comedians performing new material. Each night consists of 5x10min slots (paid bucket split) and 1x15-20min Headliner slot for new material (paid £50)', 'showcase', ARRAY['experienced', 'pro'], '{"required":false}'::jsonb, '[{"frequency":"biweekly","weekday":4,"startTime":"08:00"}]'::jsonb, '{"id":"the-salisbury-hotel-venue","name":"The Salisbury Hotel","address":"1 Grand Parade, Green Lanes, Harringay Ladder, London, N4 1JX","area":"","location":{"lat":51.58228,"lng":-0.09949}}'::jsonb, '{"contact":"Google Form on Facebook page or email odyssey@kalliscomedy.com"}'::jsonb, NULL, '{"website":"https://kalliscomedy.com/comedy-odyssey","facebook":"https://www.facebook.com/comedyodyssey","instagram":"https://instagram.com/comedyodyssey"}'::jsonb, 'active', '2021-11-14'),
