  ('comedy-through-the-looking-glass-looking-glass-cocktail-club', 'Comedy Through the Looking Glass', 'Bi-Weekly Event Structure. 4 hours in total, 2 times one hour of comedy with 5 acts doing 7-10 minute spots plus one hour with a headliner doing a 50-60 minute spot. Mixture of musicians, poets and spoken word performers.', 'showcase', ARRAY['new', 'experienced', 'pro'], '{"required":false}'::jsonb, '[{"frequency":"biweekly","weekday":3,"startTime":"18:00"}]'::jsonb, '{"id":"looking-glass-cocktail-club-venue","name":"Looking Glass Cocktail Club","address":"49 Hackney Rd, London E2 7NX","area":"","location":{"lat":51.52817,"lng":-0.07612}}'::jsonb, '{"contact":"Attend one of the bi weekly events and email andrewajt@hotmail.com with a description of your act and video clip"}'::jsonb, TRUE, '{"website":"https://www.lookingglasslondon.co.uk/"}'::jsonb, 'active', '2021-05-24'),
