  ('vauxhall-comedy-club-the-ding-dong-gong-show-vauxhall-street-food-garden-protocol-room', 'Vauxhall Comedy Club - The Ding Dong Gong Show', 'Bottom less booze outdoor comedy night. 10-15 comedic hopefuls try to last 5 minutes on stage. After an initial 60 seconds grace period the audience can decide their fate by raising a dong if they’re not entertained! 3 Dongs & You’re Gone! If they survive the 5 min they earn the chance to get a pro spot on one of our shows. Successful or not, after their set each comic gets a mini interview & is given feedback from the panel hosts', 'showcase', ARRAY[]::text[], '{"required":false}'::jsonb, '[{"frequency":"weekly","weekday":0,"startTime":"20:00"}]'::jsonb, '{"id":"vauxhall-street-food-garden-protocol-room-venue","name":"Vauxhall Street Food Garden (Protocol Room)","address":"6A S Lambeth Pl, Vauxhall, London SW8 1SP","area":"","location":{"lat":51.4852,"lng":-0.1236}}'::jsonb, '{"contact":"Form on Website"}'::jsonb, NULL, '{"website":"https://www.dingdonggongshow.com/","facebook":"https://www.facebook.com/DingDongGongShow/","instagram":"https://instagram.com/vauxhallcomedyclub"}'::jsonb, 'active', '2021-07-26'),
